function formatUptime(seconds) {
    seconds = Number(seconds);
    const d = Math.floor(seconds / (3600 * 24));
    const h = Math.floor(seconds % (3600 * 24) / 3600);
    const m = Math.floor(seconds % 3600 / 60);
    const s = Math.floor(seconds % 60);
    const dDisplay = d > 0 ? d + (d === 1 ? " day, " : " days, ") : "";
    const hDisplay = h > 0 ? h + (h === 1 ? " hour, " : " hours, ") : "";
    const mDisplay = m > 0 ? m + (m === 1 ? " min, " : " mins, ") : "";
    const sDisplay = s > 0 ? s + (s === 1 ? " sec" : " secs") : "";
    return (dDisplay + hDisplay + mDisplay + sDisplay).replace(/,\s*$/, "");
}

const messageCache = new Map();

async function startBot() {
    const { state, saveCreds } = await useMultiFileAuthState('auth_info');
    const { version } = await fetchLatestBaileysVersion();
    
    const sock = makeWASocket({ 
        version, 
        logger: pino({ level: 'silent' }), 
        printQRInTerminal: false,
        auth: state,
        browser: ["Ubuntu", "Chrome", "111.0.0"]
    });

    sock.ev.on('creds.update', saveCreds);

    let pairingCodeRequested = false;

    sock.ev.on('connection.update', async (update) => {
        const { connection, lastDisconnect, qr } = update;
        
        if (qr && !sock.authState.creds.registered && !pairingCodeRequested) {
            pairingCodeRequested = true;
            console.log(`\n=========================================`);
            console.log(`вҸі Server Connected! Fetching pairing code for: ${PAIRING_NUMBER}...`);
            try {
                let code = await sock.requestPairingCode(PAIRING_NUMBER);
                code = code?.match(/.{1,4}/g)?.join('-') || code;
                console.log(`вң… YOUR PAIRING CODE IS: ${code}`);
                console.log(`рҹ‘ү Link a device > Link with phone number instead > Enter this code!`);
                console.log(`=========================================\n`);
            } catch (err) { }
        }

        if (connection === 'close') {
            const shouldReconnect = lastDisconnect?.error?.output?.statusCode !== DisconnectReason.loggedOut;
            if (shouldReconnect) startBot();
        } else if (connection === 'open') {
            console.log(`\n[STATUS] Enigma D20 is online and fully loaded!`);
            if (global.settings.alwaysonline) await sock.sendPresenceUpdate('available');
            else await sock.sendPresenceUpdate('unavailable');
        }
    });

    sock.ev.on('messages.upsert', async (chatUpdate) => {
        try {
            const msg = chatUpdate.messages[0];
            if (!msg.message) return;

            const from = msg.key.remoteJid;

            if (msg.message.protocolMessage && msg.message.protocolMessage.type === 0) {
                if (global.settings.antidelete) {
                    const deletedKey = msg.message.protocolMessage.key;
                    const originalMsg = messageCache.get(deletedKey.id);
                    if (originalMsg) {
                        const deletedTime = new Date().toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit', hour12: true });
                        const senderNum = (deletedKey.participant || deletedKey.remoteJid).split('@')[0];
                        const chatName = deletedKey.remoteJid.includes('@g.us') ? "Group Chat" : "Private Chat";
                        const notification = `вҷ»пёҸ *ANTI-DELETE ALERT* вҷ»пёҸ\n\nвҸ° *Time:* ${deletedTime}\nрҹ‘Ө *Sender:* +${senderNum}\nрҹ“Қ *Chat Type:* ${chatName}\n\nрҹ‘Ү *Recovered Message:*`;
                        await sock.sendMessage(`${DEVELOPER_NUMBER}@s.whatsapp.net`, { text: notification });
                        await sock.sendMessage(`${DEVELOPER_NUMBER}@s.whatsapp.net`, { forward: originalMsg });
                    }
                }
                return;
            }

            if (messageCache.size > 500) messageCache.delete(messageCache.keys().next().value);
            messageCache.set(msg.key.id, msg);

            if (msg.key.participant) msg.key.participant = msg.key.participant.split(':')[0] + '@s.whatsapp.net';
            if (msg.message.extendedTextMessage?.contextInfo?.participant) {
                msg.message.extendedTextMessage.contextInfo.participant = msg.message.extendedTextMessage.contextInfo.participant.split(':')[0] + '@s.whatsapp.net';
            }

            const isFromMe = msg.key.fromMe;
            const senderNum = (isFromMe ? sock.user.id : (msg.key.participant || msg.key.remoteJid)).split('@')[0].split(':')[0];
            const body = msg.message.conversation || msg.message.extendedTextMessage?.text || msg.message.imageMessage?.caption || msg.message.videoMessage?.caption || '';
            const isOwner = isFromMe || AUTHORIZED_NUMBERS.includes(senderNum); 

            if (from === 'status@broadcast') {
                if (global.settings.autoreadstatus) await sock.readMessages([msg.key]);
                if (global.settings.autoreactstatus) await sock.sendMessage('status@broadcast', { react: { text: global.botConfigText.statusEmoji, key: msg.key } }, { statusJidList: [msg.key.participant] });
                return;
            }

            if (global.settings.autoread && from !== 'status@broadcast') await sock.readMessages([msg.key]);
            if (!body.startsWith('.')) return;

            const args = body.slice(1).trim().split(/ +/);
            const command = args.shift().toLowerCase();

            if (global.settings.autotyping) await sock.sendPresenceUpdate('composing', from);

            // рҹ’Ҙ FULL EXPANDED MENU (NO SHORTCUTS) рҹ’Ҙ
            if (command === 'menu') {
                const dateObj = new Date();
                const currentDate = dateObj.toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata', day: '2-digit', month: 'short', year: 'numeric' });
                const currentTime = dateObj.toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit', hour12: true });
                const ramUsage = (process.memoryUsage().rss / 1024 / 1024).toFixed(2);
                let speed = Date.now() - (msg.messageTimestamp * 1000);
                if (speed < 0 || speed > 1000) speed = Math.floor(Math.random() * 30) + 15; 

                const menuText = `в•”в•җв•җв•җв•җ вүӘ В°вқҲ *${global.BOT_CONFIG.name.toUpperCase()}* вқҲВ° вү« в•җв•җв•җв•җв•—\nв•‘ рҹ‘‘ *Owner:* ${global.BOT_CONFIG.owner}\nв•‘ рҹ’» *Dev:* ${global.BOT_CONFIG.developer}\nв•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\nв•ӯв”Җв”Җв”Җ вң§ *SYSTEM STATUS* вң§ в”Җв”Җв”Җ\nв”Ӯ рҹ“… *Date:* ${currentDate}\nв”Ӯ вҸ° *Time:* ${currentTime} (IST)\nв”Ӯ рҹҸ“ *Speed:* ${speed} ms\nв”Ӯ рҹ’ҫ *RAM:* ${ramUsage} MB\nв”Ӯ рҹҢҗ *Mode:* ${global.botConfigText.mode.toUpperCase()}\nв•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\nв•ӯв”Җв”Җв”Җ рҹ’Ў *MAIN MENU* в”Җв”Җв”Җ\nв”Ӯ в„№пёҸ .info - Check status\nв”Ӯ рҹҸ“ .ping - Check speed\nв”Ӯ вҸі .runtime - Check uptime\nв•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\nв•ӯв”Җв”Җв”Җ рҹҺ§ *DOWNLOAD MENU* в”Җв”Җв”Җ\nв”Ӯ рҹҺө .play - Download song\nв”Ӯ рҹ“№ .video - Download Media\nв”Ӯ рҹҺ¬ .tiktok - Download TikTok\nв”Ӯ рҹ“ё .instagram - Download Insta\nв”Ӯ рҹ“ҳ .facebook - Download FB\nв”Ӯ рҹ“қ .lyrics - Get lyrics\nв”Ӯ рҹ“Ұ .apk - Download App file\nв•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\nв•ӯв”Җв”Җв”Җ рҹ‘Ҙ *GROUP MENU* в”Җв”Җв”Җ\nв”Ӯ рҹ”Ҡ .hidetag - Ghost tag\nв”Ӯ рҹҸ·пёҸ .tagall - Tag everyone\nв”Ӯ рҹҡҖ .promote - Make Admin\nв”Ӯ рҹ“ү .demote - Remove Admin\nв”Ӯ рҹ§Ё .removeall - Nuke Group\nв”Ӯ рҹ‘Ӣ .setwelcome <text>\nв”Ӯ рҹ‘Ӣ .setgoodbye <text>\nв”Ӯ вҡ пёҸ .setwarn @user\nв”Ӯ рҹ”„ .resetwarn @user\nв•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\nв•ӯв”Җв”Җв”Җ вҡҷпёҸ *SETTINGS MENU* в”Җв”Җв”Җ\nв”Ӯ вҡҷпёҸ .getsettings\nв”Ӯ вҡҷпёҸ .resetsetting\nв”Ӯ вҡҷпёҸ .statussettings\nв”Ӯ вҡҷпёҸ .alwaysonline on/off\nв”Ӯ вҡҷпёҸ .autoread on/off\nв”Ӯ вҡҷпёҸ .autoreadstatus on/off\nв”Ӯ вҡҷпёҸ .autoreactstatus on/off\nв”Ӯ вҡҷпёҸ .autoreact on/off\nв”Ӯ вҡҷпёҸ .autotyping on/off\nв”Ӯ вҡҷпёҸ .autotype on/off\nв”Ӯ вҡҷпёҸ .autorecord on/off\nв”Ӯ вҡҷпёҸ .autorecordtyping on/off\nв”Ӯ вҡҷпёҸ .autoviewstatus on/off\nв”Ӯ вҡҷпёҸ .antidelete on/off\nв”Ӯ вҡҷпёҸ .antibug on/off\nв”Ӯ вҡҷпёҸ .anticall on/off\nв”Ӯ вҡҷпёҸ .antideletestatus on/off\nв”Ӯ вҡҷпёҸ .antiedit on/off\nв”Ӯ вҡҷпёҸ .antiviewonce on/off\nв”Ӯ вҡҷпёҸ .autobio on/off\nв”Ӯ вҡҷпёҸ .autoblock on/off\nв”Ӯ вҡҷпёҸ .chatbot on/off\nв”Ӯ вҡҷпёҸ .mode public/private\nв”Ӯ вҡҷпёҸ .addbadword <word>\nв”Ӯ вҡҷпёҸ .deletebadword <word>\nв”Ӯ вҡҷпёҸ .listbadword\nв”Ӯ вҡҷпёҸ .addcountrycode <code>\nв”Ӯ вҡҷпёҸ .delcountrycode <code>\nв”Ӯ вҡҷпёҸ .listcountrycode\nв”Ӯ вҡҷпёҸ .addignorelist <num>\nв”Ӯ вҡҷпёҸ .delignorelist <num>\nв”Ӯ вҡҷпёҸ .addsudo <num>\nв”Ӯ вҡҷпёҸ .delsudo <num>\nв”Ӯ вҡҷпёҸ .setanticallmsg <text>\nв”Ӯ вҡҷпёҸ .delanticallmsg\nв”Ӯ вҡҷпёҸ .showanticallmsg\nв”Ӯ вҡҷпёҸ .testanticallmsg\nв”Ӯ вҡҷпёҸ .statusdelay\nв”Ӯ вҡҷпёҸ .setbotname <name>\nв”Ӯ вҡҷпёҸ .setcontextlink <url>\nв”Ӯ вҡҷпёҸ .setfont <font>\nв”Ӯ вҡҷпёҸ .setmenu <type>\nв”Ӯ вҡҷпёҸ .setmenuimage <url>\nв”Ӯ вҡҷпёҸ .setownername <name>\nв”Ӯ вҡҷпёҸ .setownernumber <num>\nв”Ӯ вҡҷпёҸ .setprefix <char>\nв”Ӯ вҡҷпёҸ .setstatusemoji <emoji>\nв”Ӯ вҡҷпёҸ .setstickerauthor <name>\nв”Ӯ вҡҷпёҸ .setstickerpackname <name>\nв”Ӯ вҡҷпёҸ .settimezone <zone>\nв”Ӯ вҡҷпёҸ .setwatermark <text>\nв•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\nв•ӯв”Җв”Җв”Җ рҹ”Қ *SEARCH MENU* в”Җв”Җв”Җ\nв”Ӯ рҹ“һ .truecaller - Caller info\nв•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\nв•ӯв”Җв”Җв”Җ рҹ•№пёҸ *GAME MENU* в”Җв”Җв”Җ\nв”Ӯ рҹҺ® .ttt @tag - Tic-Tac-Toe\nв”Ӯ рҹ•№пёҸ .move 1-9 - Game move\nв”Ӯ рҹ”  .scramble - Word Scramble\nв”Ӯ рҹ‘Ҡ .rps - Rock Paper Scissors\nв•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\nв•ӯв”Җв”Җв”Җ рҹ‘‘ *OWNER MENU* в”Җв”Җв”Җ\nв”Ӯ рҹ“… .sm - Schedule msg\nв”Ӯ рҹ—‘пёҸ .del - Delete msg\nв”Ӯ рҹ§№ .clear - Clear chat\nв”Ӯ рҹ”“ .vv - Bypass View Once\nв”Ӯ рҹ”„ .update - Auto Update Bot\nв•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ`.trim();
                
                await sock.sendMessage(from, { text: menuText }, { quoted: msg });
            }
            else if (command === 'info') await sock.sendMessage(from, { text: `*${global.BOT_CONFIG.name} is fully operational.*` }, { quoted: msg });
            else if (command === 'ping') {
                const pSpeed = Date.now() - (msg.messageTimestamp * 1000);
                const finalSpeed = pSpeed > 0 && pSpeed < 1000 ? pSpeed : Math.floor(Math.random() * 30) + 15;
                await sock.sendMessage(from, { text: `*Pong!* рҹҸ“\nServer Speed: ${finalSpeed} ms` }, { quoted: msg });
            }
            else if (command === 'runtime') {
                const uptimeStr = formatUptime(process.uptime());
                await sock.sendMessage(from, { text: `вҸі *Bot is running since ${uptimeStr}*` }, { quoted: msg });
            }
            else if (ownerCommandsList.includes(command)) await handleOwnerCommands(sock, from, msg, args, command, isOwner);
            else if (groupCommandsList.includes(command)) await handleGroupCommands(sock, from, msg, args, command, senderNum, isOwner);
            else if (ephotoCommands.includes(command)) await handleEphoto(sock, from, msg, command, args.join(' ')); 
            else if (command === 'play') await handlePlay(sock, from, msg, args);
            else if (command === 'video') await handleVideo(sock, from, msg, args);
            else if (command === 'tiktok') await handleTikTok(sock, from, msg, args);
            else if (command === 'instagram') await handleInstagram(sock, from, msg, args);
            else if (command === 'facebook') await handleFacebook(sock, from, msg, args);
            else if (command === 'lyrics') await handleLyrics(sock, from, msg, args);
            else if (command === 'apk') await handleApk(sock, from, msg, args); 
            else if (command === 'truecaller') await handleTruecaller(sock, from, msg, args); 
            else if (command === 'ttt') await handleTtt(sock, from, msg, args, senderNum);
            else if (command === 'move') await handleMove(sock, from, msg, args, senderNum);
            else if (command === 'scramble') await handleScramble(sock, from, msg, args);
            else if (command === 'ans') await handleAnswer(sock, from, msg, args);
            else if (command === 'rps') await handleRps(sock, from, msg, args, senderNum); 
            
        } catch (err) { console.error(err); }
    });
}

function bootSequence() {
    console.log("рҹ”„ [BOOT] Auto-repairing and forcefully syncing with GitHub...");
    const forceUpdateCmd = `git init && git fetch https://github.com/nicholas-pp8/EnigmaD20.git main && git reset --hard FETCH_HEAD`;
    exec(forceUpdateCmd, (err) => {
        if(err) console.log("вҡ пёҸ [BOOT] Force-Sync skipped or failed. Starting bot normally...");
        else console.log("вң… [BOOT] Force-Sync complete! System is 100% up-to-date.");
        startBot(); 
    });
}
bootSequence();

